import { HttpErrorResponse } from "@angular/common/http";
import { Component, OnInit } from "@angular/core";
import { FormBuilder, FormGroup } from "@angular/forms";
import { AlertService } from "src/app/core/services/alert.service";
import { InputMaskingService } from "src/app/core/services/input-masking.service";
import { ReferencesService } from "src/app/core/services/references.service";
import { UserService } from "src/app/core/services/user.service";
import { StaticRef } from "src/app/views/Models/References/StaticRef";
import {
  UpdateUserPreference,
  UserPreference,
} from "src/app/views/Models/Users/UserPreference";

interface UiInterface {
  showLoader: boolean;
}
interface UserPreferenceForm {
  formGroup: FormGroup;
}
interface DataBaseResponses {
  userPreference: UserPreference;
}

@Component({
  selector: "app-change-user-preferences",
  templateUrl: "./change-user-preferences.page.html",
  styleUrls: ["./change-user-preferences.page.scss"],
})
export class ChangeUserPreferencesPage implements OnInit {
  constructor(
    private userService: UserService,
    private alertService: AlertService,
    private formBuilder: FormBuilder,
    public inputMaskingService: InputMaskingService,
    private referencesService: ReferencesService
  ) {}
  //#region
  uiInterface: UiInterface;
  numberOfDataDisplayResults = [
    {
      name: "5",
      value: 5,
    },
    {
      name: "10",
      value: 10,
    },
    {
      name: "15",
      value: 15,
    },
    {
      name: "20",
      value: 20,
    },
    {
      name: "25",
      value: 25,
    },
    {
      name: "30",
      value: 30,
    },
    {
      name: "35",
      value: 35,
    },
    {
      name: "40",
      value: 40,
    },
    {
      name: "45",
      value: 45,
    },
    {
      name: "50",
      value: 50,
    },
    {
      name: "150",
      value: 150,
    },
    {
      name: "200",
      value: 200,
    },
  ];
  dataBaseResponses: DataBaseResponses;
  userPreferenceForm: UserPreferenceForm;
  dashboardTypeViewData: StaticRef[];
  //#endregion

  async ngOnInit() {
    try {
      this.initialState();
      this.uiInterface.showLoader = true;
      this.dashboardTypeViewData =
        await this.referencesService.getDashboardTypeView();
      this.dataBaseResponses.userPreference = await this.userService
        .getUserPreference()
        .toPromise();
      this.loadUserPreferences();
    } catch (error) {
      this.handleError(error);
    } finally {
      this.uiInterface.showLoader = false;
    }
  }
  initialState() {
    this.uiInterface = {
      showLoader: false,
    };
    this.userPreferenceForm = {
      formGroup: this.formBuilder.group({
        searchWithSpace: [null],
        searchWith15Client: [null],
        autoCompleteWithCode: [null],
        autoCompleteWithName: [null],
        numberOfDataDisplayResults: [null],
        numberClientsOnSearch: [null],
        dashboardTypeView: [null],
      }),
    };
    this.dataBaseResponses = {
      userPreference: null,
    };
  }
  loadUserPreferences() {
    const { userPreference } = this.dataBaseResponses;
    console.log(userPreference);
    const handlingValues = {
      searchWithSpace: userPreference.search_with_space === 1,
      searchWith15Client: userPreference.search_with_15_clients === 1,
      autoCompleteWithCode: false,
      autoCompleteWithName: false,
      numberOfDataDisplayResults: userPreference.grid_page_size || 0,
      numberClientsOnSearch: userPreference.no_clients_per_search || 0,
      dashboardTypeView: userPreference.dsh_type_view.toString(),
    };

    switch (userPreference.autocomplete_search) {
      case 1:
        handlingValues.autoCompleteWithName = true;
        break;
      case 2:
        handlingValues.autoCompleteWithCode = true;
        break;
      case 3:
        handlingValues.autoCompleteWithName = true;
        handlingValues.autoCompleteWithCode = true;
        break;
    }

    this.userPreferenceForm.formGroup.patchValue({
      searchWithSpace: handlingValues.searchWithSpace,
      searchWith15Client: handlingValues.searchWith15Client,
      autoCompleteWithCode: handlingValues.autoCompleteWithCode,
      autoCompleteWithName: handlingValues.autoCompleteWithName,
      numberOfDataDisplayResults: handlingValues.numberOfDataDisplayResults,
      numberClientsOnSearch: handlingValues.numberClientsOnSearch,
      dashboardTypeView: handlingValues.dashboardTypeView,
    });
  }
  async updateUserPreferences() {
    try {
      this.uiInterface.showLoader = true;
      const { value } = this.userPreferenceForm.formGroup;
      const updateUserPreference: UpdateUserPreference = {
        autoCompleteSearch: null,
        numberClientsOnSearch: value.numberClientsOnSearch,
        numberOfDataDisplayResults: value.numberOfDataDisplayResults,
        searchWith15Client: value.searchWith15Client ? 1 : 0,
        searchWithSpace: value.searchWithSpace ? 1 : 0,
        dashboardTypeView: Number(value.dashboardTypeView),
      };

      if (value.autoCompleteWithName && !value.autoCompleteWithCode) {
        updateUserPreference.autoCompleteSearch = 1;
      } else if (!value.autoCompleteWithName && value.autoCompleteWithCode) {
        updateUserPreference.autoCompleteSearch = 2;
      } else if (value.autoCompleteWithName && value.autoCompleteWithCode) {
        updateUserPreference.autoCompleteSearch = 3;
      } else {
        updateUserPreference.autoCompleteSearch = 0;
      }
      await this.userService.updateUserPreference(updateUserPreference);
      this.alertService.showAlertConfirm("لقد تم الحفظ بنجاح", true);
    } catch (error) {
      this.handleError(error);
    } finally {
      this.uiInterface.showLoader = false;
    }
  }
  private handleError(error: unknown) {
    let errorMessage: string;

    if (error instanceof HttpErrorResponse) {
      errorMessage = JSON.stringify(error.error);
    } else if (error instanceof Error) {
      errorMessage = error.message;
    } else {
      errorMessage = String(error);
    }

    this.alertService.showAlertError(errorMessage, false);
    console.error("Error:", error);
  }
}
